{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time earnings breakdown visibility for drivers across three jurisdictions with fundamentally different labor classifications, legal requirements, and institutional approval processes. This is not a simple UI feature — it is a compensation transparency system with legal compliance obligations that vary by jurisdiction.",
    "bounded_context": "Driver Earnings / Compensation Transparency",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed or time-based compensation a driver receives for being available or completing a shift, independent of delivery volume. For employees (CA, DE), this maps to hourly/salaried wage. For contractors (ID), this maps to a per-engagement base rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to each completed delivery. Must be clearly distinguished from base pay in all jurisdictions to avoid wage-calculation errors." },
      { "term": "Tips", "definition": "Voluntary payments from customers directed to the driver. Tips are the driver's property and must never be applied toward satisfying base pay or minimum wage obligations." },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings. For employees: taxes, benefits, garnishments. For contractors: platform fees, equipment charges. Must be individually itemized, never aggregated into a single line." },
      { "term": "Gross Earnings", "definition": "Sum of Base Pay + Per-Delivery Bonus + Tips, before any deductions." },
      { "term": "Net Earnings", "definition": "Gross Earnings minus all Deductions. The amount actually paid out to the driver." },
      { "term": "Driver Classification", "definition": "The legal employment relationship — employee or independent contractor — which determines applicable labor law, required disclosures, and deduction types." },
      { "term": "Earnings Period", "definition": "The time window over which earnings are aggregated and displayed. Must align with the pay cycle for employees and the settlement cycle for contractors." },
      { "term": "Wage Statement", "definition": "In California, a legally mandated itemized document per Labor Code §226. The earnings breakdown display effectively becomes this document and must meet all statutory requirements." },
      { "term": "Works Council Approval (Betriebsrat)", "definition": "In Germany, mandatory co-determination approval from the employee works council before any system that displays or monitors compensation data can be deployed. This is a legal deployment gate, not a courtesy consultation." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Earnings components (Base Pay + Per-Delivery Bonus + Tips - Deductions) must always sum to the displayed Net Earnings. No rounding discrepancies, no unaccounted amounts.",
      "invariant": true,
      "invariant_justification": "If the sum does not balance, the system is displaying financially incorrect data. This is a data integrity constraint — a broken ledger.",
      "testable_assertion": "For any driver at any point in time: BasePay + PerDeliveryBonus + Tips - SumOfAllDeductions == NetEarnings, to the cent."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be counted toward, offset against, or used to satisfy base pay or minimum wage obligations.",
      "invariant": true,
      "invariant_justification": "In California, tip credit is prohibited (Labor Code §351). Violating this is wage theft. Even in jurisdictions without this law, treating tips as base pay is a domain corruption — tips are customer-to-driver transfers, not employer compensation.",
      "testable_assertion": "No calculation path exists where increasing tip amount reduces base pay or where tip amount is included in minimum wage compliance checks."
    },
    {
      "id": "BR-3",
      "rule": "Every deduction must be individually itemized with a label, amount, and legal/contractual basis. Deductions must never be displayed as a single aggregated total.",
      "invariant": true,
      "invariant_justification": "California Labor Code §226 requires itemized deductions on wage statements. Aggregating deductions makes legal compliance impossible and hides potentially unauthorized deductions from drivers.",
      "testable_assertion": "The deductions section always contains ≥1 named line item when total deductions > 0. No line item labeled 'Other' or 'Miscellaneous' exceeds a configurable threshold without further breakdown."
    },
    {
      "id": "BR-4",
      "rule": "In California, the earnings display must satisfy all requirements of Labor Code §226 itemized wage statements: gross wages, total hours worked, piece-rate units (deliveries), all deductions itemized, net wages, pay period dates, employer name and address, employee name and last four of SSN or employee ID.",
      "invariant": true,
      "invariant_justification": "This is a statutory requirement. Non-compliance exposes the platform to penalties of $250 per violation per employee per pay period, plus private right of action.",
      "testable_assertion": "For California drivers classified as employees, the earnings display contains all nine §226-required fields. Omission of any field fails validation."
    },
    {
      "id": "BR-5",
      "rule": "The Germany rollout must not proceed until documented Betriebsrat approval is recorded in the system. The feature must be feature-flagged per jurisdiction and the Germany flag must default to OFF.",
      "invariant": true,
      "invariant_justification": "German Works Constitution Act (Betriebsverfassungsgesetz) §87 grants co-determination rights on compensation transparency systems. Deploying without approval is a legal violation that can result in injunctions and invalidation of the system.",
      "testable_assertion": "The Germany jurisdiction feature flag cannot be set to ON without an associated WorksCouncilApproval record with status=APPROVED and a valid approval date."
    },
    {
      "id": "BR-6",
      "rule": "Driver classification (employee vs. contractor) determines the set of allowed deduction types and required display fields. The system must enforce classification-specific schemas — employee deductions (taxes, benefits) must never appear on contractor views and vice versa (platform fees).",
      "invariant": true,
      "invariant_justification": "Displaying employee-type deductions to a contractor (or vice versa) constitutes misclassification evidence that regulators actively look for. This is a legal exposure invariant.",
      "testable_assertion": "Given a driver with classification=CONTRACTOR, no deduction of type TAX_WITHHOLDING, BENEFITS, or GARNISHMENT appears. Given classification=EMPLOYEE, no deduction of type PLATFORM_FEE or EQUIPMENT_RENTAL appears."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must be displayed in the local currency of the driver's operating jurisdiction with locale-appropriate formatting.",
      "invariant": false,
      "invariant_justification": "This is a UX/compliance best practice. A VP could decide to also show USD equivalent, but the primary display currency is a strong policy.",
      "testable_assertion": "California displays USD ($), Germany displays EUR (€), Indonesia displays IDR (Rp). Currency symbol and decimal formatting match locale conventions."
    },
    {
      "id": "BR-8",
      "rule": "The 'real-time' display must reflect earnings no more stale than the platform's delivery-completion event processing latency. Earnings must update upon each delivery completion event, not on a batch/polling schedule.",
      "invariant": false,
      "invariant_justification": "The exact staleness threshold is a product decision, but event-driven updates are a strong business requirement. A VP could relax to near-real-time with a defined SLA.",
      "testable_assertion": "Within T seconds (configurable, default 30) of a delivery-completion event, the driver's earnings display reflects the updated amounts."
    },
    {
      "id": "BR-9",
      "rule": "In Indonesia, where drivers are independent contractors, the earnings display must clearly label the relationship as a contractor arrangement and must not use employment terminology (salary, wages, employer).",
      "invariant": false,
      "invariant_justification": "This is a misclassification risk mitigation policy. Using employee language for contractors could be used as evidence of misclassification in future legal challenges.",
      "testable_assertion": "For Indonesia drivers, no UI string contains the words 'salary', 'wages', 'employer', or 'employee'. Labels use 'earnings', 'service fees', 'platform', 'partner'."
    },
    {
      "id": "BR-10",
      "rule": "Earnings data is personally identifiable financial information. Access must be restricted to the authenticated driver viewing their own data. No driver may view another driver's earnings.",
      "invariant": true,
      "invariant_justification": "Cross-driver earnings visibility is a data privacy violation under GDPR (Germany), CCPA (California), and basic PII protection principles. System corruption if violated.",
      "testable_assertion": "Any API request for earnings data where requestor_driver_id != target_driver_id returns 403 Forbidden."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A California driver classified as an employee who has completed 3 deliveries in the current pay period",
      "when": "The driver opens the earnings breakdown screen",
      "then": "They see Base Pay, Per-Delivery Bonus (3 units), Tips, and individually itemized Deductions (tax withholding, etc.), all summing correctly to Net Earnings, plus all §226 required fields (hours worked, pay period dates, employer info, employee ID)"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany where the Betriebsrat has NOT yet approved the feature",
      "when": "The feature is deployed globally",
      "then": "Germany drivers do not see the earnings breakdown feature at all — the feature flag is OFF and no partial or preview version is shown"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany where the Betriebsrat HAS approved the feature with documented approval",
      "when": "An admin activates the Germany feature flag",
      "then": "The system verifies a WorksCouncilApproval record exists with status=APPROVED before allowing the flag to be set to ON"
    },
    {
      "id": "AC-4",
      "given": "An Indonesian driver classified as an independent contractor who has completed a delivery",
      "when": "The driver views their earnings breakdown",
      "then": "They see Base Rate, Per-Delivery Bonus, Tips, and any Platform Fees itemized, using contractor-appropriate language — no employment terminology appears anywhere in the UI"
    },
    {
      "id": "AC-5",
      "given": "A driver has just completed a delivery and the delivery-completion event has been processed",
      "when": "The driver views their earnings breakdown within 30 seconds",
      "then": "The new delivery's earnings components are reflected in the displayed totals"
    },
    {
      "id": "AC-6",
      "given": "A California driver with $50 base pay, $15 delivery bonus (3 × $5), $12 tips, $8.50 federal tax withholding, and $3.20 state tax withholding",
      "when": "They view their earnings breakdown",
      "then": "Gross Earnings shows $77.00, Deductions shows two separate line items ($8.50 Federal Tax, $3.20 State Tax), and Net Earnings shows $65.30"
    },
    {
      "id": "AC-7",
      "given": "Driver A is authenticated and requests the earnings API endpoint with Driver B's ID",
      "when": "The API processes the request",
      "then": "The request is rejected with 403 Forbidden and an audit log entry is created"
    },
    {
      "id": "AC-8",
      "given": "A driver with $0 tips and $0 deductions in the current period",
      "when": "They view their earnings breakdown",
      "then": "Tips and Deductions sections are still visible but show $0.00 — they are never hidden, so drivers always know these categories exist"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A delivery is disputed or reversed after the driver has already seen it in their real-time earnings",
      "expected_behavior": "The reversal must appear as a separate, clearly labeled negative line item (e.g., 'Delivery Reversal - Order #X') — never silently reduce a previous amount. The audit trail must show both the original credit and the reversal."
    },
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., starts a delivery in one state, completes in another)",
      "expected_behavior": "Earnings classification and display rules follow the driver's registered operating jurisdiction, not the delivery origin/destination. This must be a conscious, documented policy decision."
    },
    {
      "scenario": "Customer adds or modifies a tip after the driver has already viewed their earnings for that delivery",
      "expected_behavior": "The updated tip must appear as a new event in the earnings timeline. The previously displayed tip amount must remain visible in history with a clear 'Updated' indicator, not silently overwritten."
    },
    {
      "scenario": "A German driver transfers to California (jurisdiction change while feature is live)",
      "expected_behavior": "The earnings display schema must switch to the California §226-compliant format from the effective date of the jurisdiction change. Historical earnings remain displayed under the original jurisdiction's format."
    },
    {
      "scenario": "Concurrent delivery completions arrive out of order (delivery B completes before delivery A but A's event arrives first)",
      "expected_behavior": "Earnings display must be eventually consistent and correct. Each delivery's contribution must be individually identifiable regardless of processing order. Running totals must never show a state that was never true."
    },
    {
      "scenario": "A deduction exceeds the driver's gross earnings for the period, resulting in negative net pay",
      "expected_behavior": "The system must display the negative balance clearly. In California, certain deductions that would bring pay below minimum wage are prohibited — the system must enforce jurisdiction-specific deduction caps before displaying."
    },
    {
      "scenario": "The platform introduces a new earnings component (e.g., surge pricing bonus) not in the original four categories",
      "expected_behavior": "The earnings schema must be extensible. New components must slot into the breakdown without requiring a schema migration. In California, any new component must be evaluated for §226 compliance. In Germany, the addition of a new compensation component likely requires fresh Betriebsrat consultation."
    },
    {
      "scenario": "Real-time update infrastructure is degraded — delivery events are delayed beyond the staleness SLA",
      "expected_behavior": "The UI must show a 'last updated' timestamp and a visible indicator that data may be stale. Never show stale data without disclosure — this is especially critical in California where the wage statement must be accurate."
    }
  ],

  "business_impact": {
    "financial": "California non-compliance with §226 carries penalties of $250/violation/employee/pay period (first violation), escalating to $1,000 for subsequent violations, plus attorney's fees in private actions. Class action exposure is significant given driver volume. Germany rollout without Betriebsrat approval can result in injunctions halting the entire feature. Upside: transparent earnings reduce payment disputes and support ticket volume (est. 15-30% reduction in pay-related support contacts).",
    "operational": "This feature creates a per-jurisdiction compliance surface that must be maintained independently. Each labor law change in any jurisdiction requires a schema and display review. The Betriebsrat approval process in Germany introduces a non-engineering dependency with unpredictable timeline (weeks to months). Engineering must build jurisdiction-aware feature flagging from day one — this is not optional.",
    "user": "Drivers gain trust and confidence in the platform through pay transparency. This directly impacts driver retention and recruitment — platforms with opaque pay face higher churn. Real-time visibility reduces end-of-period pay surprises that drive negative sentiment and churn.",
    "risk": "HIGH risk in California due to §226's strict requirements and active plaintiff's bar. MEDIUM risk in Germany due to Betriebsrat process — timeline uncertainty, not legal exposure if process is followed. LOW legal risk in Indonesia but MEDIUM misclassification risk if employment language leaks into contractor UI. Cross-jurisdiction data architecture risk: a single-schema approach will fail; jurisdiction-specific schemas are required from the start.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Legally entitled to this information. Feature must be complete and §226-compliant — partial rollout is not an option. Directly impacts their ability to verify correct pay." },
      { "group": "Drivers (Germany)", "impact": "Cannot receive this feature until works council approves. Must not see any preview or beta version. Delay is a legal necessity, not a product choice." },
      { "group": "Drivers (Indonesia)", "impact": "Receive transparency as a benefit, but language and framing must protect contractor classification. Incorrectly framed feature could undermine platform's legal position." },
      { "group": "Legal/Compliance Team", "impact": "Must review and sign off on jurisdiction-specific display formats before launch. Ongoing obligation to monitor labor law changes in all three jurisdictions." },
      { "group": "Finance/Payroll", "impact": "Earnings breakdown data must be sourced from the same system of record as actual payroll. Any discrepancy between displayed earnings and actual payout creates legal and trust exposure." },
      { "group": "Customer Support", "impact": "Expected reduction in pay-related tickets, but new category of tickets around display discrepancies, staleness, and reversal visibility. Must be trained on jurisdiction-specific earnings rules." },
      { "group": "German Works Council (Betriebsrat)", "impact": "Must be engaged as a co-decision-maker, not merely informed. Has legal authority to block or modify the feature. Requires detailed documentation of what data is shown and how." },
      { "group": "Platform (Corporate)", "impact": "Competitive advantage in driver acquisition if executed well. Regulatory and litigation exposure if executed poorly. Sets precedent for transparency standard across future jurisdictions." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is underspecified in several legally critical areas. 'Real time' is not defined with an SLA. 'Deductions' is not enumerated per jurisdiction. The spec does not mention California §226 requirements, which are non-negotiable for an employee earnings display — this is a significant gap. The spec does not address what happens when the Betriebsrat process is underway (no timeline, no interim state). The three-jurisdiction model with mixed classifications (employee/contractor) requires legal review that no engineering team should attempt without counsel sign-off.",
    "high_confidence_areas": [
      "Earnings must sum correctly (arithmetic invariant)",
      "Tips must not offset base pay",
      "Betriebsrat approval is a hard gate for Germany",
      "Driver classification determines display schema",
      "PII access controls on earnings data"
    ],
    "low_confidence_areas": [
      "Exact §226 field requirements — need legal review of current statute text",
      "Deduction taxonomy per jurisdiction — spec does not enumerate allowed deduction types",
      "Definition of 'real time' — no SLA specified, business must define acceptable staleness",
      "Cross-jurisdiction driver scenarios — spec silent on drivers who operate in multiple jurisdictions",
      "Indonesia-specific regulatory requirements — spec says 'no requirement' but local counsel should verify"
    ],
    "assumptions": [
      "California drivers are classified as employees per AB5 with no exemptions applying",
      "The platform has an existing payroll/settlement system that is the source of truth for earnings data",
      "The Betriebsrat engagement has not yet begun for Germany",
      "Indonesia's characterization as having 'no pay transparency requirement' has been verified by local counsel",
      "The earnings display will serve as the §226 wage statement for California, not a separate system"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "'Real time' is undefined. For a compensation display with legal implications, the staleness SLA matters enormously. Is this event-driven (sub-second after delivery completion)? Near-real-time (within minutes)? Per-shift? The answer affects architecture, cost, and legal compliance (California wage statements must be accurate at time of issuance).",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering", "Legal/Compliance"],
      "options": ["Event-driven: update within seconds of delivery completion", "Near-real-time: update within 30-60 seconds via streaming", "Periodic: update every 5-15 minutes via polling"],
      "recommendation": "Event-driven with a documented SLA of ≤30 seconds. Anything less frequent risks showing inaccurate data to drivers who are actively completing deliveries."
    },
    {
      "type": "ambiguity",
      "description": "'Deductions' is not enumerated. The types of deductions vary dramatically by driver classification and jurisdiction. Employee deductions (tax withholding, benefits, garnishments) are legally regulated. Contractor deductions (platform fees, equipment) are contractually governed. The spec must define the deduction taxonomy per jurisdiction before implementation.",
      "affected_stakeholders": ["Drivers", "Legal/Compliance", "Finance/Payroll"],
      "options": ["Define a fixed deduction taxonomy per jurisdiction now", "Build an extensible deduction type registry that legal can configure per jurisdiction"],
      "recommendation": "Extensible registry. Deduction types will change as labor law evolves, benefits change, and new jurisdictions are added. Hard-coding is a maintenance trap."
    },
    {
      "type": "missing_context",
      "description": "The spec does not reference California Labor Code §226, which imposes specific field requirements on any itemized wage statement shown to employees. If this earnings display serves as or supplements the wage statement, it must include: gross wages earned, total hours worked, number of piece-rate units, all deductions, net wages, pay period dates, employee name + ID, and employer name + address. This is not optional.",
      "affected_stakeholders": ["Drivers (California)", "Legal/Compliance", "Platform (Corporate)"],
      "options": ["Treat earnings display as the official §226 wage statement and include all required fields", "Treat it as supplementary to a separate §226-compliant wage statement"],
      "recommendation": "Treat as the official statement. Maintaining two parallel compensation display systems is wasteful and increases discrepancy risk. But this MUST be reviewed by employment counsel before committing."
    },
    {
      "type": "missing_context",
      "description": "No guidance on Betriebsrat engagement timeline or interim state for Germany. What do German drivers see while the approval process is underway? A blank state? A message explaining the feature is coming? Nothing? This is a product and legal decision with UX implications.",
      "affected_stakeholders": ["Drivers (Germany)", "German Works Council", "Product"],
      "options": ["Show nothing — feature is invisible until approved", "Show a placeholder explaining the feature is pending works council review", "Show a limited version (e.g., total earnings only, no breakdown) if that doesn't trigger co-determination"],
      "recommendation": "Show nothing. Any visible reference to the feature before Betriebsrat approval risks being interpreted as a unilateral rollout. Safest approach is complete invisibility."
    }
  ],

  "rejection_reasons": []
}

